import sys
class Solution:
    def solve(self, nums: list[int]) -> int:
        dp = [0] * (len(nums) + 1)
        dp[0] = 0
        dp[1] = nums[0]
        for i in range(2, len(nums) + 1):
            dp[i] = min(dp[i-1], dp[i-2] if i >= 2 else 0) + nums[i-1]
        return dp[-1]

def main():
    nums = list(map(int, input().split()))
    n = len(nums)
    solution = Solution()
    print(solution.solve(nums))

if __name__ == '__main__':
    main()
